// Makefile

# 设置Go的版本
GO_VERSION := 1.18
# 设置项目名称
PROJECT_NAME := user-service
# 设置构建输出目录
BUILD_DIR := ./build
# 设置测试输出目录
TEST_DIR := ./test
# 设置二进制文件名
BINARY_NAME := $(PROJECT_NAME)

# Go环境变量
GOPATH := $(shell go env GOPATH)
GOBIN := $(shell go env GOBIN)
GO := go
TEST := go test

# 创建构建目录
all: setup build test

setup:
	@mkdir -p $(BUILD_DIR)
	@mkdir -p $(TEST_DIR)

# 下载Go环境
download-go:
	@curl -sSf https://golang.org/dl/go$(GO_VERSION).linux-amd64.tar.gz | tar -C /usr/local -xzf -
	@echo "Go $(GO_VERSION) installed"

# 安装依赖
install:
	@$(GO) mod tidy

# 构建微服务
build:
	@$(GO) build -o $(BUILD_DIR)/$(BINARY_NAME) ./cmd/$(PROJECT_NAME)

# 运行测试
test:
	@$(TEST) ./...

# 静态分析
static-check:
	@$(GO) vet ./...

# 清理构建和测试目录
clean:
	@rm -rf $(BUILD_DIR) $(TEST_DIR)

# 打包微服务
package:
	@tar -czf $(BINARY_NAME).tar.gz -C $(BUILD_DIR) $(BINARY_NAME)

# 安装依赖并运行测试
run-test:
	@$(GO) mod tidy && $(TEST) ./...

# 使用Go modules时的版本替换规则
%.go:
	@$(GO) mod download

.PHONY: all setup download-go install build test static-check clean package run-test %.go
```

