// 下面是一个简单的 TypeScript 服务实现，其中包含了一个错误处理机制。

class ServiceError extends Error {
  constructor(message: string, public statusCode: number) {
    super(message);
    this.name = "ServiceError";
  }
}

class MyService {
  // 假设这是一个可能抛出错误的函数
  async performAction(): Promise<any> {
    try {
      // 模拟一个可能出错的操作
      const result = await this.someAsyncOperation();
      return result;
    } catch (error) {
      // 将错误转换为 ServiceError
      if (error instanceof Error) {
        throw new ServiceError(error.message, 500);
      } else {
        throw new ServiceError("An unknown error occurred", 500);
      }
    }
  }

  private async someAsyncOperation(): Promise<any> {
    // 这里应该是一些异步操作，例如数据库查询等
    // 为了示例，我们模拟一个错误
    throw new Error("Something went wrong");
  }

  // 错误处理中间件
  static handleError(error: ServiceError): void {
    console.error(`Error: ${error.message}, Status Code: ${error.statusCode}`);
    // 这里可以根据不同的状态码发送不同的响应给客户端
    // 例如，如果是一个 404 错误，我们可以返回一个友好的消息
